#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    // Read entire stdin into a buffer
    char *input = NULL;
    size_t size = 0;
    {
        char buf[1024];
        while (1) {
            size_t n = fread(buf, 1, sizeof(buf), stdin);
            if (n == 0) break;
            input = realloc(input, size + n + 1);
            memcpy(input + size, buf, n);
            size += n;
        }
        if (input) input[size] = '\0';
    }
    if (!input) return 0;
    // Replace literal "\\n" with a space
    for (size_t i = 0; i + 1 < size; ++i) {
        if (input[i] == '\\' && input[i+1] == 'n') {
            input[i] = ' ';
            memmove(input + i + 1, input + i + 2, size - i - 1);
            size -= 1;
        }
    }
    // Parse N
    int N;
    int offset = 0;
    if (sscanf(input, "%d%n", &N, &offset) != 1) return 0;
    int *a = malloc(N * sizeof(int));
    const char *p = input + offset;
    for (int i = 0; i < N; ++i) {
        while (*p && (*p==' '||*p=='\t'||*p=='\r'||*p=='\n')) p++;
        int val; int consumed;
        if (sscanf(p, "%d%n", &val, &consumed) != 1) break;
        a[i] = val;
        p += consumed;
    }
    for (int i = 0; i < N; ++i) {
        if (i) printf(" ");
        printf("%d", a[i]);
    }
    return 0;
}

