    int N; if(!(ss>>N)) return 0;
    vector<int> a(N);
    for(int i=0;i<N;++i) ss>>a[i];
    for(int i=0;i<N;++i){
        if(i) cout<<' ';
        cout<<a[i];
    }
    return 0;
